mapper.select:
SELECT o.id, o.user_id, o.org_name, o.org_type, o.contact_name, o.phone, o.address, o.credential_url, o.audit_status, o.reject_reason, o.audit_time, o.create_time FROM t_downstream_org o WHERE 1=1
AND (o.org_name LIKE CONCAT('%', #{keyword}, '%') OR o.contact_name LIKE CONCAT('%', #{keyword}, '%') OR o.phone LIKE CONCAT('%', #{keyword}, '%'))
AND o.audit_status = #{auditStatus}
AND o.org_type = #{orgType}
ORDER BY o.create_time DESC
